import api from '../app/client';

import type { AddressDTO, UserProfile } from '../../types/dto';

export type { UserProfile };

export const profileService = {
  getMe: () =>
    api.get<UserProfile>('/account/me').then(r => r.data),

  updateProfile: (data: {
    firstName: string;
    middleName?: string | null;
    lastName: string;
    phoneNumber?: string | null;
    currentAddress?: AddressDTO | null;
    timeZone?: string | null;
  }) => api.put('/account/update-profile', data).then(r => r.data),

  deleteProfilePicture: () =>
    api.delete('/account/profile-picture').then(r => r.data),
};
