import { useEffect, useRef, useState } from "react";
import { toast } from "sonner";
import { profileService, type UserProfile } from "@/api/auth/profileService";
import { authService } from "@/api/auth/authService";
import { getApiErrorMessage } from "@/api/app/apiError";
import { uploadService } from "@/api/uploadService";
import { useAuth } from "@/shared/AuthContext";
import {
  Shield,
  MapPin,
  Key,
  Loader2,
  Eye,
  EyeOff,
  Pencil,
  Trash2,
  UserCircle,
} from "lucide-react";
import { Button } from "@/shadcn/components/ui/button";
import { Input } from "@/shadcn/components/ui/input";
import { Label } from "@/shadcn/components/ui/label";
import { Badge } from "@/shadcn/components/ui/badge";
import HarmonyForm from "@/components/forms/HarmonyForm";
import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import { UserAvatar } from "@/components/ui/UserAvatar";

function InfoRow({ label, value }: { label: string; value?: string | null }) {
  return (
    <div className="flex justify-between items-center py-2.5 border-b border-border/20 last:border-0">
      <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">{label}</span>
      <span className="text-sm font-semibold text-foreground">{value || "—"}</span>
    </div>
  );
}

function AddressBlock({ address }: { address: NonNullable<UserProfile["currentAddress"]> }) {
  const namePart = [address.firstName, address.lastName].filter(Boolean).join(" ");
  return (
    <div className="space-y-1 text-sm">
      {namePart && <p className="font-semibold text-foreground">{namePart}</p>}
      {address.addressLine && <p className="text-muted-foreground">{address.addressLine}</p>}
      {(address.city || address.state || address.zipCode) && (
        <p className="text-muted-foreground">
          {[address.city, address.state, address.zipCode].filter(Boolean).join(", ")}
        </p>
      )}
      {address.country && <p className="text-muted-foreground">{address.country}</p>}
    </div>
  );
}

const MyProfile = () => {
  const { profilePictureVersion, setProfilePictureVersion } = useAuth();
  const [data, setData] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [editOpen, setEditOpen] = useState(false);
  const [pwOpen, setPwOpen] = useState(false);

  const [pwData, setPwData] = useState({ oldPassword: "", newPassword: "", confirmPassword: "" });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [editError, setEditError] = useState("");
  const [pwError, setPwError] = useState("");

  const photoInputRef = useRef<HTMLInputElement | null>(null);

  const [showOld, setShowOld] = useState(false);
  const [showNew, setShowNew] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  const fetchUserProfile = async () => {
    try {
      const profile = await profileService.getMe();
      setData(profile);
      setProfilePictureVersion(profile.profilePictureVersion ?? null);
    } catch (err) {
      setError(getApiErrorMessage(err, "Failed to fetch profile."));
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUserProfile();
  }, []);

  const handleProfileUpdate = async (formData: any) => {
    setIsSubmitting(true);
    setEditError("");
    try {
      const mapAddress = (addr: any): import("@/types/dto").AddressDTO | undefined =>
        addr?.AddressLine
          ? {
              firstName:   addr.FirstName   ?? "",
              lastName:    addr.LastName    ?? "",
              addressLine: addr.AddressLine,
              city:        addr.City        ?? "",
              state:       addr.State       ?? "",
              zipCode:     addr.ZipCode     ?? "",
              country:     addr.Country     ?? "",
            }
          : undefined;

      await profileService.updateProfile({
        firstName:      formData.FirstName ?? "",
        middleName:     formData.MiddleName,
        lastName:       formData.LastName ?? "",
        phoneNumber:    formData.PhoneNumber,
        currentAddress: mapAddress(formData.CurrentAddress),
        timeZone:       formData.TimeZone,
      });

      setData({
        ...data!,
        firstName:      formData.FirstName,
        middleName:     formData.MiddleName,
        lastName:       formData.LastName,
        phoneNumber:    formData.PhoneNumber,
        timeZone:       formData.TimeZone,
        fullName:       [formData.FirstName, formData.MiddleName, formData.LastName].filter(Boolean).join(" "),
        currentAddress: mapAddress(formData.CurrentAddress),
      });
      setEditOpen(false);
    } catch (err) {
      setEditError(getApiErrorMessage(err, "Update failed"));
    } finally {
      setIsSubmitting(false);
    }
  };

  const handlePasswordUpdate = async () => {
    if (pwData.newPassword.length < 16) {
      setPwError("Password must be at least 16 characters");
      return;
    }
    if (pwData.newPassword !== pwData.confirmPassword) {
      setPwError("Passwords do not match");
      return;
    }
    setPwError("");
    setIsSubmitting(true);
    try {
      await authService.changePassword({
        oldPassword: pwData.oldPassword,
        newPassword: pwData.newPassword,
      });
      setPwData({ oldPassword: "", newPassword: "", confirmPassword: "" });
      setPwOpen(false);
    } catch (err) {
      setPwError(getApiErrorMessage(err, "Update failed"));
    } finally {
      setIsSubmitting(false);
    }
  };

  if (loading)
    return (
      <div className="flex items-center justify-center min-h-100">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );

  if (error)
    return (
      <div className="max-w-md mx-auto mt-20 p-8 bg-card rounded-lg shadow border border-destructive/20">
        <h3 className="text-lg font-bold text-destructive mb-2">Error Loading Profile</h3>
        <p className="text-destructive/80 text-sm">{error}</p>
        <Button className="mt-6 w-full" onClick={() => window.location.reload()}>
          Retry
        </Button>
      </div>
    );

  if (!data) return null;

  return (
    <div className="page-wrapper flex flex-col" style={{ gap: "var(--section-padding)" }}>

      {/* ── Page Header ─────────────────────────────────────────────────────── */}
      <div className="flex items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <div className="size-12 flex items-center justify-center rounded-[var(--radius-lg)] bg-primary/10 shrink-0">
            <UserCircle className="w-7 h-7 text-primary" />
          </div>
          <div>
            <h1 className="page-title">My Profile</h1>
            <p className="page-subtitle">View and manage your account information.</p>
          </div>
        </div>
        <div className="flex items-center gap-2 shrink-0">
          <Button
            variant="outline"
            size="sm"
            onClick={() => { setPwError(""); setPwOpen(true); }}
          >
            <Key size={14} /> Change Password
          </Button>
          <Button size="sm" onClick={() => { setEditError(""); setEditOpen(true); }}>
            Edit Profile
          </Button>
        </div>
      </div>

      {/* ── Profile Overview card ────────────────────────────────────────────── */}
      <div className="bg-card rounded-xl border border-border shadow-sm p-6">
        <div className="flex flex-col sm:flex-row items-center gap-[var(--section-padding)]">

          {/* Avatar with photo upload */}
          <div className="relative shrink-0">
            <UserAvatar
              userId={data.id}
              firstName={data.firstName}
              lastName={data.lastName}
              pictureSize="profile"
              cacheKey={profilePictureVersion ?? undefined}
              className="w-40 h-40 rounded-2xl border border-border"
              fallbackClassName="rounded-2xl text-4xl"
            />
            <button
              onClick={() => photoInputRef.current?.click()}
              className="absolute -bottom-2 -right-2 p-1.5 bg-card rounded-lg shadow border border-border text-primary hover:bg-muted transition-colors"
              title="Change profile picture"
            >
              <Pencil size={12} />
            </button>
            {data.profilePictureUrl && (
              <button
                onClick={async () => {
                  try {
                    await profileService.deleteProfilePicture();
                    setProfilePictureVersion(null);
                    setData(prev => prev ? { ...prev, profilePictureUrl: null, profilePictureVersion: null } : prev);
                    toast.success("Profile picture removed.");
                  } catch (err) {
                    toast.error(getApiErrorMessage(err, "Failed to remove profile picture."));
                  }
                }}
                className="absolute -bottom-2 -left-2 p-1.5 bg-card rounded-lg shadow border border-border text-destructive hover:bg-muted transition-colors"
                title="Remove profile picture"
              >
                <Trash2 size={12} />
              </button>
            )}
            <input
              ref={photoInputRef}
              type="file"
              accept="image/*"
              className="hidden"
              onChange={async (e) => {
                const file = e.target.files?.[0];
                if (!file) return;
                try {
                  await uploadService.upload("/account/upload-profile-picture", file);
                  await fetchUserProfile();
                  toast.success("Profile picture updated.");
                } catch (err) {
                  toast.error(getApiErrorMessage(err, "Failed to update profile picture."));
                } finally {
                  e.target.value = "";
                }
              }}
            />
          </div>

          {/* Name + email */}
          <div className="min-w-0">
            <h2 className="text-xl font-bold text-foreground truncate">
              {data.fullName || "User Profile"}
            </h2>
            <p className="text-sm text-muted-foreground mt-0.5">{data.email}</p>
          </div>

          {/* Roles */}
          {data.roles && data.roles.length > 0 && (
            <>
              <div className="hidden sm:block w-px h-12 bg-border self-center shrink-0" />
              <div className="flex flex-col gap-1.5 shrink-0">
                <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider mb-0.5">Roles</p>
                {data.roles.map((role) => (
                  <Badge
                    key={role}
                    variant="outline"
                    className="bg-primary/10 text-primary border-primary/20 text-[10px] font-bold uppercase tracking-wider rounded-full justify-center"
                  >
                    {role}
                  </Badge>
                ))}
              </div>
              <div className="hidden sm:block w-px h-12 bg-border self-center shrink-0" />
            </>
          )}

          {/* Key identifiers */}
          <div className="flex flex-wrap gap-x-8 gap-y-3 shrink-0">
            {data.employeeID && (
              <div>
                <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider">Employee ID</p>
                <p className="text-sm font-bold text-foreground">{data.employeeID}</p>
              </div>
            )}
            {data.joiningDate && (
              <div>
                <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider">Joining Date</p>
                <p className="text-sm font-bold text-foreground">{data.joiningDate}</p>
              </div>
            )}
            {data.leavingDate && (
              <div>
                <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider">Leaving Date</p>
                <p className="text-sm font-bold text-foreground">{data.leavingDate}</p>
              </div>
            )}
            {data.reasonForLeaving && (
              <div>
                <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider">Reason</p>
                <p className="text-sm font-bold text-foreground">{data.reasonForLeaving}</p>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* ── 4-card details grid ───────────────────────────────────────────── */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6">

        {/* Personal Details */}
        <div className="bg-card rounded-xl border border-border shadow-sm overflow-hidden">
          <div className="px-6 py-4 border-b border-border flex items-center gap-2">
            <UserCircle size={16} className="text-primary" />
            <h3 className="text-sm font-semibold text-foreground">Personal Details</h3>
          </div>
          <div className="p-6">
            <InfoRow label="First Name" value={data.firstName} />
            <InfoRow label="Middle Name" value={data.middleName} />
            <InfoRow label="Last Name" value={data.lastName} />
            <InfoRow label="Email" value={data.email} />
            <InfoRow label="Phone" value={data.phoneNumber} />
            <InfoRow label="Time Zone" value={data.timeZone} />
          </div>
        </div>

        {/* System Identity */}
        <div className="bg-card rounded-xl border border-border shadow-sm overflow-hidden">
          <div className="px-6 py-4 border-b border-border flex items-center gap-2">
            <Shield size={16} className="text-primary" />
            <h3 className="text-sm font-semibold text-foreground">System Identity</h3>
          </div>
          <div className="p-6">
            <InfoRow label="Birth Date" value={data.birthDate} />
            <InfoRow label="PAN" value={data.pan} />
            <InfoRow label="Aadhaar" value={data.aadhar} />
            <InfoRow label="Status" value={data.active ? "Active" : "Inactive"} />
          </div>
        </div>

        {/* Current Address */}
        <div className="bg-card rounded-xl border border-border shadow-sm overflow-hidden">
          <div className="px-6 py-4 border-b border-border flex items-center gap-2">
            <MapPin size={16} className="text-primary" />
            <h3 className="text-sm font-semibold text-foreground">Current Address</h3>
          </div>
          <div className="p-6">
            {data.currentAddress ? (
              <AddressBlock address={data.currentAddress} />
            ) : (
              <p className="text-sm text-muted-foreground italic">Not set</p>
            )}
          </div>
        </div>

        {/* Permanent Address */}
        <div className="bg-card rounded-xl border border-border shadow-sm overflow-hidden">
          <div className="px-6 py-4 border-b border-border flex items-center gap-2">
            <MapPin size={16} className="text-primary" />
            <h3 className="text-sm font-semibold text-foreground">Permanent Address</h3>
          </div>
          <div className="p-6">
            {data.permanentAddress ? (
              <AddressBlock address={data.permanentAddress} />
            ) : (
              <p className="text-sm text-muted-foreground italic">Not set</p>
            )}
          </div>
        </div>
      </div>

      {/* ── Edit Profile dialog ──────────────────────────────────────────────── */}
      <HarmonyDialog
        open={editOpen}
        onOpenChange={setEditOpen}
        title="Edit Profile"
        description="Update your personal information."
        size="xl"
        formId="edit-profile-form"
        submitLabel="Save Changes"
        isSubmitting={isSubmitting}
      >
        {editError && (
          <p className="text-sm text-destructive mb-4">{editError}</p>
        )}
        <HarmonyForm
          id="edit-profile-form"
          dtoName="UpdateProfileDTO"
          mode="edit"
          initialValues={{
            FirstName:   data.firstName,
            MiddleName:  data.middleName,
            LastName:    data.lastName,
            PhoneNumber: data.phoneNumber,
            TimeZone:    data.timeZone,
            CurrentAddress: data.currentAddress
              ? {
                  FirstName:   data.currentAddress.firstName,
                  LastName:    data.currentAddress.lastName,
                  AddressLine: data.currentAddress.addressLine,
                  City:        data.currentAddress.city,
                  State:       data.currentAddress.state,
                  ZipCode:     data.currentAddress.zipCode,
                  Country:     data.currentAddress.country,
                }
              : null,
          }}
          onSubmit={handleProfileUpdate}
          hideSubmitButton
          isPending={isSubmitting}
        />
      </HarmonyDialog>

      {/* ── Change Password dialog ───────────────────────────────────────────── */}
      <HarmonyDialog
        open={pwOpen}
        onOpenChange={(open) => {
          if (isSubmitting) return;
          if (!open) {
            setPwData({ oldPassword: "", newPassword: "", confirmPassword: "" });
            setPwError("");
            setShowOld(false);
            setShowNew(false);
            setShowConfirm(false);
          }
          setPwOpen(open);
        }}
        title="Change Password"
        description="Your password must be at least 16 characters."
        size="md"
        onSubmit={handlePasswordUpdate}
        submitLabel="Update Password"
        isSubmitting={isSubmitting}
      >
        <div className="space-y-4">
          {[
            { label: "Current Password",  key: "oldPassword"     as const, show: showOld,     toggle: () => setShowOld(s => !s) },
            { label: "New Password",      key: "newPassword"     as const, show: showNew,     toggle: () => setShowNew(s => !s),     placeholder: "Min. 16 characters" },
            { label: "Confirm Password",  key: "confirmPassword" as const, show: showConfirm, toggle: () => setShowConfirm(s => !s), placeholder: "Repeat new password" },
          ].map(({ label, key, show, toggle, placeholder }) => (
            <div key={key} className="space-y-1.5">
              <Label>{label}</Label>
              <div className="relative">
                <Input
                  type={show ? "text" : "password"}
                  value={pwData[key]}
                  onChange={(e) => setPwData(prev => ({ ...prev, [key]: e.target.value }))}
                  placeholder={placeholder ?? "Enter password"}
                  className="pr-10"
                />
                <button
                  type="button"
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                  onClick={toggle}
                >
                  {show ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
            </div>
          ))}
          {pwError && <p className="text-sm text-destructive">{pwError}</p>}
        </div>
      </HarmonyDialog>

    </div>
  );
};

export default MyProfile;
